                    item.isToday
                      ? "bg-indigo-50/70 dark:bg-indigo-950/20 border-indigo-500/50 shadow-md ring-2 ring-indigo-500/5 animate-pulse-slow"
                      : isAboveAverage 
                        ? "bg-emerald-5/20 dark:bg-emerald-950/5 border-emerald-100/50 dark:border-emerald-900/20 hover:border-emerald-300" 
                        : "bg-slate-50/50 dark:bg-slate-850/30 border-slate-100 dark:border-slate-800/60 hover:border-indigo-300"
